class JsonResponseResponseGenerator(ResponseGenerator[Response]):
    model = "mistralai/Mixtral-8x22B-Instruct-v0.1"
    params = dict(stop=["\n", "###"])
    params.update(config.get("chat", dict()))
    name = "json_response"

    def __init__(self):
        super(JsonResponseResponseGenerator, self).__init__()
        self.verbosity = config.get("verbosity", "info")
        self.response_config = config.get("chat.json_response", None)    

    def generate(self, message: Message) -> Response:
        response = super(JsonResponseResponseGenerator, self).generate(message)

        if response.status == "error" and response.message.startswith("invalid json"):
            self.log.warning(f"{response.message}")
                # remove the first error message, since a lot of times they overlap and contain parts of both error messages.
                response.message = response.message.split('\n')[1:]
                # make one of the messages better readable
                response.message = '\n'.join(['  '.join(f'{a}{b}') if b else a for a, b in zip(response.message, response.message[1:]) + [""]])
        self.log.info(f"json: {response}")
        try:
            return Response(content=json.loads(response.content))
        except:
            return Response(content=json.dumps(json.loads(response.content)))

class InvalidJsonResponseResponseGenerator:
    model = "mistralai/Mixtral-8x22B-Instruct-v0.1"
