import { formatDistanceFromNow } from 'date-fns';
import { chatList } from './constants';

const chatItem: any = {
  id: '',
  image: '',
  title: '',
  lastMsg: '',
  createdAt: '',
  user: '',
  isPrivate: false,
  content: ''
};

export class ChatSummary {
  public static addChatId = (item: {}, chat_id: string): string => {
    return item?.id || '';
  };

  public static getChat = (id: string): any => {
    return chatList.find((obj) => {
      return obj?.id === id;
    });
  };

  public static addChat = (
    item: {},
    chat_id: string,
    is_private: boolean
  ): string => {
    const id = this.addChatId(item, chat_id);
    const user = item?.user;
    // const title = item?.title;
    const msg = item?.msg;
    const image = item?.image;
    const created_at = (item as {})?.created_at;
    // const user = item.user;
    // const isPrivate = true || false;
    item = { ...chatItem };
    item.id = id;
    item.image = image;
    item.lastMsg = msg;
    item.createdAt = created_at;
    item.title = msg ? msg.slice(0, 20) : '';
    item.isPrivate = is_private;

    for (const entry of chatList) {
      // console.log(item.id);
      if (item.id === id) {
        // console.log(item.title+' - item.title');
        // item.title = entry.title;
      }
    }
    return item;
  };

  public static deletechat = (id: string) => {
    try {
      const index = chatList.findIndex((item) => item.id === id);
      if (index > -1) {
        chatList.splice(index, 1);
      }
    } catch (err) {}
  };

  public static removeMsg = (id: string) => {
    const obj = this.getChat(id);
    if (obj) {
      // console.log(obj);
      obj.content = '';
      obj.lastMsg = '';
      obj.title = obj.lastMsg.slice(0, 20) || '';
      obj.updatedAt = '';
    }
  };

  public static getFirstMsg = (id: string) => {
    const obj = this.getChat(id);
    if (obj && obj.content) {
      return obj?.firstMsg;
    } else return '';
  };

  public static updateUser = (chat: {} = {}, user: string): {} => {
    chat.user = user;
    chat.updatedAt = new Date().toLocaleString();
    return chat;
  };

  // public static updateChat = (chat: {}, chat_id: string) => {
  //   const arr = this.getChat(chat_id);
  //   chat.createdAt = arr.createdAt;
  //   chat.updatedAt = new Date().toLocaleString();
  //   return chat;
  // };

  public static getChatDate = (id: string) => {
    const obj = this.getChat(id);
    if (obj) {
      const today = new Date();
      today.setHours(0, 0, 0, 0);
      const chatDate = new Date(obj.created_at);
      chatDate.setHours(0, 0, 0, 0);
      return formatDistanceFromNow(chatDate, { addSuffix: true });
    }
    return '';
  };

  // public static updateChat

