def _get_questionnaire_responses(self) -> Dict[str, str]:
    return {
        "questionnaire_value": self._get_last_response_dict(self.questionnaire),
        "instruction": self.task.get("instruction"),
        "statement": self.task["question"],
        "response": self._get_last_response(self.questionnaire),
        "score": self.questionnaire_value,
        "response_length": len(self._get_last_response(self.questionnaire)) + 5,
    }

def check_consistency(
    response: Dict[str, str], target: str, threshold: float = 0.8
) -> bool:
    """Return True if the string 'response' has the given prefix 'target'"""
    expected = re.escape(target)
    pattern = f"^(?P=\\k<target>)"

    response = re.sub(r"\s+", " ", response)  # normalize whitespace
    return bool(re.match(pattern, response))


def sanitize_instruction(instruction: str) -> str:
    return instruction.replace("answer only with", "answer only with a number")


def sanitize_reasoning(reasoning: str) -> str:
    return reasoning

