    def process_turbo_response(self, response, is_follow_up=False) -> Dict:
        """

        Processes the response from TurboChat.
        The response should have the following format:
          {
            "token_id": int,  # Always the same, not important
            "token_text": str,
            ...
          }
        """

        message_id = "1"

        if self.model.endswith("llama"):
            model_type = "llama"
            score = self.tokenizer.special_tokens_ids.get("<|reserved_special_token_36|>")[-1]  # Get reserved token ID
        else:
            model_type = "gemma"
            score = self.tokenizer.special_tokens_ids.get("<|end|>")  # Get reserved token ID

        data = parse_message_json(response, model_type)
        data.update({"score": score, "message_id": message_id})
        data = process_json_data(data)

        if is_follow_up:
            return data["response"]
        else:
            return data

