            model_type = "llama"
            score = self.tokenizer.special_tokens_ids.get("<|reserved_special_token_36|>")[-1]  # Get reserved token ID
        else:
            model_type = "gemma"
            score = self.tokenizer.special_tokens_ids.get("<|end|>")  # Get reserved token ID

        data = parse_message_json(response, model_type)
        data.update(
            {
                "score": score,
                "message_id": message_id,
                "followed_responses": [parse_message_json(followed_response, model_type)],
            }
